export type Subject = 'Math' | 'Science' | 'English' | 'General';

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  imageUrl?: string;
  audioData?: string;
  isQuiz?: boolean;
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
}

export interface UserProfile {
  name: string;
  age: number;
  grade: string;
}

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, Subject } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getGeminiExplanation = async (
  prompt: string, 
  userProfile: UserProfile, 
  subject: Subject
) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const systemInstruction = `You are a friendly, enthusiastic, and patient AI tutor for children aged ${userProfile.age}. 
  The student is in ${userProfile.grade}. 
  Current subject: ${subject}. 
  Guidelines:
  - Use simple language, metaphors, and fun examples appropriate for a ${userProfile.age}-year-old.
  - Break down complex topics into small, bite-sized steps.
  - Be encouraging! Use phrases like "Great question!", "You've got this!", or "Let's explore this together!".
  - If the student asks something outside Math, Science, or English, gently steer them back or answer briefly then return to learning.
  - Format your response with clear headings and bullet points using Markdown.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction,
      temperature: 0.7,
    },
  });

  return response.text;
};

export const generateEducationalImage = async (topic: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { text: `A vibrant, clear, and child-friendly educational illustration of: ${topic}. Digital art style, professional educational quality, no scary elements, high contrast, suitable for a school textbook.` },
      ],
    },
    config: {
      imageConfig: { aspectRatio: "1:1" }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const generateQuiz = async (topic: string, userProfile: UserProfile) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a 3-question multiple choice quiz about ${topic} for a ${userProfile.age}-year-old.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctAnswer: { type: Type.INTEGER, description: "Index of the correct option (0-indexed)" },
            explanation: { type: Type.STRING }
          },
          required: ["question", "options", "correctAnswer", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const textToSpeech = async (text: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Read this in a friendly, helpful teacher voice: ${text}` }] }],
    config: {
      responseModalities: ["AUDIO"],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  BookOpen, 
  Atom, 
  Calculator, 
  MessageCircle, 
  Star, 
  User, 
  ChevronRight, 
  Volume2, 
  BrainCircuit,
  Lightbulb,
  Sparkles,
  Send,
  Loader2
} from 'lucide-react';
import { Subject, UserProfile, ChatMessage, QuizQuestion } from './types';
import { 
  getGeminiExplanation, 
  generateEducationalImage, 
  generateQuiz, 
  textToSpeech 
} from './services/gemini';
import { decode, decodeAudioData } from './utils/audio';

// --- Sub-components ---

const Onboarding: React.FC<{ onComplete: (profile: UserProfile) => void }> = ({ onComplete }) => {
  const [name, setName] = useState('');
  const [age, setAge] = useState(10);
  const [grade, setGrade] = useState('Grade 5');

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-blue-400 via-indigo-400 to-purple-500">
      <div className="bg-white rounded-3xl shadow-2xl p-8 max-w-md w-full animate-in fade-in zoom-in duration-500">
        <div className="text-center mb-8">
          <div className="bg-yellow-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
            <Sparkles className="text-yellow-500 w-12 h-12" />
          </div>
          <h1 className="text-3xl font-bold text-gray-800 mb-2">Welcome to EduGemini!</h1>
          <p className="text-gray-600">Let's set up your learning profile</p>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">What's your name?</label>
            <input 
              type="text" 
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none transition"
              placeholder="Enter your name"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">How old are you?</label>
              <input 
                type="number" 
                min="7" 
                max="15"
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none transition"
                value={age}
                onChange={(e) => setAge(parseInt(e.target.value))}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1">Grade Level</label>
              <select 
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none transition bg-white"
                value={grade}
                onChange={(e) => setGrade(e.target.value)}
              >
                {[...Array(9)].map((_, i) => (
                  <option key={i} value={`Grade ${i + 1}`}>Grade {i + 1}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        <button 
          onClick={() => name && onComplete({ name, age, grade })}
          disabled={!name}
          className="w-full mt-8 py-4 bg-blue-600 text-white font-bold rounded-2xl hover:bg-blue-700 transition transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg"
        >
          Let's Start Learning!
        </button>
      </div>
    </div>
  );
};

const QuizCard: React.FC<{ quiz: QuizQuestion[], onFinish: () => void }> = ({ quiz, onFinish }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [selected, setSelected] = useState<number | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [score, setScore] = useState(0);
  const [showExplanation, setShowExplanation] = useState(false);

  const handleCheck = (idx: number) => {
    setSelected(idx);
    const correct = idx === quiz[currentIdx].correctAnswer;
    setIsCorrect(correct);
    if (correct) setScore(s => s + 1);
    setShowExplanation(true);
  };

  const nextQuestion = () => {
    if (currentIdx < quiz.length - 1) {
      setCurrentIdx(currentIdx + 1);
      setSelected(null);
      setIsCorrect(null);
      setShowExplanation(false);
    } else {
      onFinish();
    }
  };

  const q = quiz[currentIdx];

  return (
    <div className="bg-white rounded-2xl p-6 shadow-md border-2 border-yellow-200">
      <div className="flex justify-between items-center mb-4">
        <span className="text-sm font-bold text-yellow-600 bg-yellow-50 px-3 py-1 rounded-full uppercase tracking-wider">
          Quiz: {currentIdx + 1} of {quiz.length}
        </span>
        <span className="text-sm font-bold text-gray-500">Score: {score}</span>
      </div>

      <h3 className="text-xl font-bold text-gray-800 mb-6">{q.question}</h3>

      <div className="space-y-3 mb-6">
        {q.options.map((opt, i) => (
          <button
            key={i}
            onClick={() => !showExplanation && handleCheck(i)}
            disabled={showExplanation}
            className={`w-full text-left p-4 rounded-xl border-2 transition transform active:scale-[0.98] ${
              selected === i 
                ? (isCorrect ? 'bg-green-50 border-green-500' : 'bg-red-50 border-red-500')
                : 'bg-white border-gray-100 hover:border-blue-200 hover:bg-blue-50'
            } ${showExplanation && i === q.correctAnswer ? 'bg-green-50 border-green-500' : ''}`}
          >
            <div className="flex items-center">
               <div className={`w-8 h-8 rounded-full flex items-center justify-center mr-3 font-bold ${
                  selected === i 
                    ? (isCorrect ? 'bg-green-500 text-white' : 'bg-red-500 text-white')
                    : 'bg-gray-100 text-gray-500'
               } ${showExplanation && i === q.correctAnswer ? 'bg-green-500 text-white' : ''}`}>
                 {String.fromCharCode(65 + i)}
               </div>
               <span className="font-medium text-gray-700">{opt}</span>
            </div>
          </button>
        ))}
      </div>

      {showExplanation && (
        <div className="animate-in slide-in-from-top duration-300">
          <div className={`p-4 rounded-xl mb-6 ${isCorrect ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'}`}>
            <p className="font-bold mb-1">{isCorrect ? '🌟 Spot on!' : 'Oops! Not quite.'}</p>
            <p className="text-sm opacity-90">{q.explanation}</p>
          </div>
          <button 
            onClick={nextQuestion}
            className="w-full py-3 bg-blue-600 text-white rounded-xl font-bold shadow-md hover:bg-blue-700 transition"
          >
            {currentIdx === quiz.length - 1 ? 'Finish Quiz' : 'Next Question'}
          </button>
        </div>
      )}
    </div>
  );
};

// --- Main App Component ---

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [activeSubject, setActiveSubject] = useState<Subject>('General');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeQuiz, setActiveQuiz] = useState<QuizQuestion[] | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || !profile || isLoading) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const explanation = await getGeminiExplanation(input, profile, activeSubject);

      const assistantMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: explanation || "I'm having a little trouble thinking right now. Let's try again!",
      };

      setMessages(prev => [...prev, assistantMessage]);

      // Automatically generate a visual aid for complex topics or if requested
      if (input.length > 10 || explanation?.length > 500) {
        const imageUrl = await generateEducationalImage(input);
        if (imageUrl) {
          setMessages(prev => prev.map(m => m.id === assistantMessage.id ? { ...m, imageUrl } : m));
        }
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const startQuiz = async (topic: string) => {
    if (!profile || isLoading) return;
    setIsLoading(true);
    try {
      const quiz = await generateQuiz(topic, profile);
      setActiveQuiz(quiz);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const playTTS = async (text: string) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;

    try {
      const audioBase64 = await textToSpeech(text.substring(0, 500)); // Limit length for speed
      if (audioBase64) {
        const buffer = await decodeAudioData(decode(audioBase64), ctx, 24000, 1);
        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);

        const startTime = Math.max(ctx.currentTime, nextStartTimeRef.current);
        source.start(startTime);
        nextStartTimeRef.current = startTime + buffer.duration;
      }
    } catch (err) {
      console.error("TTS failed", err);
    }
  };

  if (!profile) {
    return <Onboarding onComplete={setProfile} />;
  }

  return (
    <div className="flex flex-col h-screen bg-gray-50 text-gray-900">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10 shadow-sm">
        <div className="flex items-center space-x-3">
          <div className="bg-blue-600 p-2 rounded-xl">
            <BrainCircuit className="text-white w-6 h-6" />
          </div>
          <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600">EduGemini</h1>
        </div>

        <div className="flex items-center space-x-4">
          <div className="hidden md:flex items-center px-3 py-1 bg-yellow-100 text-yellow-700 rounded-full text-sm font-bold border border-yellow-200">
            <Star className="w-4 h-4 mr-1 fill-yellow-500" />
            Hello, {profile.name}!
          </div>
          <button className="p-2 rounded-full hover:bg-gray-100 transition">
            <User className="w-6 h-6 text-gray-600" />
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col md:flex-row overflow-hidden">
        {/* Sidebar / Subject Selection */}
        <aside className="w-full md:w-64 bg-white border-r border-gray-200 p-4 space-y-2 flex-shrink-0">
          <p className="text-xs font-bold text-gray-400 uppercase tracking-widest px-2 mb-4">Pick a Subject</p>
          <button 
            onClick={() => setActiveSubject('General')}
            className={`w-full flex items-center p-3 rounded-2xl transition ${activeSubject === 'General' ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'hover:bg-gray-50 text-gray-600'}`}
          >
            <MessageCircle className="w-5 h-5 mr-3" />
            <span className="font-bold">General Chat</span>
          </button>
          <button 
            onClick={() => setActiveSubject('Math')}
            className={`w-full flex items-center p-3 rounded-2xl transition ${activeSubject === 'Math' ? 'bg-green-500 text-white shadow-lg shadow-green-200' : 'hover:bg-gray-50 text-gray-600'}`}
          >
            <Calculator className="w-5 h-5 mr-3" />
            <span className="font-bold">Math Adventure</span>
          </button>
          <button 
            onClick={() => setActiveSubject('Science')}
            className={`w-full flex items-center p-3 rounded-2xl transition ${activeSubject === 'Science' ? 'bg-purple-500 text-white shadow-lg shadow-purple-200' : 'hover:bg-gray-50 text-gray-600'}`}
          >
            <Atom className="w-5 h-5 mr-3" />
            <span className="font-bold">Science Lab</span>
          </button>
          <button 
            onClick={() => setActiveSubject('English')}
            className={`w-full flex items-center p-3 rounded-2xl transition ${activeSubject === 'English' ? 'bg-orange-500 text-white shadow-lg shadow-orange-200' : 'hover:bg-gray-50 text-gray-600'}`}
          >
            <BookOpen className="w-5 h-5 mr-3" />
            <span className="font-bold">English Story</span>
          </button>

          <div className="mt-8 p-4 bg-indigo-50 rounded-2xl border border-indigo-100">
             <div className="flex items-center mb-2 text-indigo-700">
                <Lightbulb className="w-4 h-4 mr-2" />
                <span className="text-sm font-bold">Pro Tip</span>
             </div>
             <p className="text-xs text-indigo-600 leading-relaxed">
               Ask me to "Explain like I'm 5" or "Show me a picture" for extra fun!
             </p>
          </div>
        </aside>

        {/* Chat / Content Area */}
        <section className="flex-1 flex flex-col min-h-0 bg-gray-50 relative">
          <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6">
            {messages.length === 0 && !activeQuiz && (
              <div className="flex flex-col items-center justify-center h-full text-center space-y-6 max-w-2xl mx-auto">
                <div className="w-32 h-32 bg-white rounded-full flex items-center justify-center shadow-xl animate-bounce">
                  {activeSubject === 'Math' ? <Calculator className="w-16 h-16 text-green-500" /> :
                   activeSubject === 'Science' ? <Atom className="w-16 h-16 text-purple-500" /> :
                   activeSubject === 'English' ? <BookOpen className="w-16 h-16 text-orange-500" /> :
                   <Sparkles className="w-16 h-16 text-blue-500" />}
                </div>
                <div>
                  <h2 className="text-3xl font-bold text-gray-800 mb-2">Let's explore {activeSubject}!</h2>
                  <p className="text-lg text-gray-600">What do you want to learn about today? I can explain gravity, fractions, or even how to write a poem!</p>
                </div>
                <div className="flex flex-wrap justify-center gap-3">
                  {['Why is the sky blue?', 'How do decimals work?', 'What is a metaphor?', 'Teach me about photosynthesis'].map(suggestion => (
                    <button 
                      key={suggestion}
                      onClick={() => setInput(suggestion)}
                      className="px-4 py-2 bg-white border border-gray-200 rounded-full text-sm font-semibold text-gray-600 hover:bg-blue-50 hover:border-blue-300 hover:text-blue-600 transition"
                    >
                      {suggestion}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {activeQuiz && (
              <div className="max-w-3xl mx-auto py-12">
                <QuizCard quiz={activeQuiz} onFinish={() => setActiveQuiz(null)} />
              </div>
            )}

            {!activeQuiz && messages.map((msg) => (
              <div 
                key={msg.id} 
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}
              >
                <div className={`flex max-w-[85%] md:max-w-[70%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'} items-start`}>
                  <div className={`w-10 h-10 rounded-2xl flex-shrink-0 flex items-center justify-center shadow-sm ${msg.role === 'user' ? 'bg-blue-600 ml-3' : 'bg-white border border-gray-200 mr-3'}`}>
                    {msg.role === 'user' ? <User className="text-white w-6 h-6" /> : <BrainCircuit className="text-blue-600 w-6 h-6" />}
                  </div>
                  <div className={`rounded-3xl p-4 shadow-sm relative ${msg.role === 'user' ? 'bg-blue-600 text-white rounded-tr-none' : 'bg-white border border-gray-200 rounded-tl-none text-gray-800'}`}>
                    <div className="whitespace-pre-wrap leading-relaxed text-sm md:text-base prose prose-slate">
                       {msg.content}
                    </div>
                    {msg.imageUrl && (
                      <div className="mt-4 rounded-2xl overflow-hidden border border-gray-100 shadow-lg bg-gray-50">
                        <img src={msg.imageUrl} alt="AI Generated Aid" className="w-full h-auto object-cover max-h-96" />
                        <div className="p-3 bg-white text-xs font-bold text-gray-400 uppercase">Visual Learning Aid</div>
                      </div>
                    )}
                    {msg.role === 'assistant' && (
                      <div className="flex items-center space-x-2 mt-4 pt-4 border-t border-gray-100">
                        <button 
                          onClick={() => playTTS(msg.content)}
                          className="flex items-center space-x-1 text-xs font-bold text-blue-600 hover:bg-blue-50 px-2 py-1 rounded-full transition"
                        >
                          <Volume2 className="w-4 h-4" />
                          <span>Read Aloud</span>
                        </button>
                        <button 
                          onClick={() => startQuiz(msg.content.substring(0, 50))}
                          className="flex items-center space-x-1 text-xs font-bold text-purple-600 hover:bg-purple-50 px-2 py-1 rounded-full transition"
                        >
                          <Star className="w-4 h-4" />
                          <span>Quick Quiz</span>
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start animate-pulse">
                <div className="flex flex-row items-center">
                  <div className="w-10 h-10 rounded-2xl bg-white border border-gray-200 mr-3 flex items-center justify-center">
                    <Loader2 className="w-5 h-5 text-blue-500 animate-spin" />
                  </div>
                  <div className="bg-white border border-gray-200 rounded-3xl px-4 py-2 text-sm font-bold text-gray-400">
                    Gemini is thinking...
                  </div>
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input Area */}
          {!activeQuiz && (
            <div className="p-4 bg-white border-t border-gray-200">
              <form 
                onSubmit={handleSendMessage}
                className="max-w-4xl mx-auto flex items-center space-x-2"
              >
                <div className="flex-1 relative group">
                  <input 
                    type="text" 
                    placeholder={`Ask your ${activeSubject} question...`}
                    className="w-full pl-6 pr-12 py-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none transition shadow-inner"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    disabled={isLoading}
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center space-x-2">
                    <button 
                      type="submit"
                      disabled={!input.trim() || isLoading}
                      className="bg-blue-600 text-white p-2 rounded-xl hover:bg-blue-700 transition transform active:scale-95 disabled:opacity-50 shadow-md"
                    >
                      {isLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
                    </button>
                  </div>
                </div>
              </form>
              <p className="text-center text-[10px] text-gray-400 mt-2">
                EduGemini makes learning fun. Always double-check facts with your teachers!
              </p>
            </div>
          )}
        </section>
      </main>
    </div>
  );
};

export default App;
